import { PikaAPI } from './api.js';
import { setupDiscord, authorize } from './discord.js';

const api = new PikaAPI();
let modulesCache = [];
let currentFilter = 'all';
let settingsModalOpen = false;

const $ = (s) => document.querySelector(s);
const $$ = (s) => document.querySelectorAll(s);

function toast(msg, type) {
  const container = document.getElementById('toast-container') || (() => {
    const el = document.createElement('div');
    el.id = 'toast-container';
    el.className = 'toast-container';
    document.body.appendChild(el);
    return el;
  })();
  const t = document.createElement('div');
  t.className = `toast ${type || 'success'}`;
  t.textContent = msg;
  container.appendChild(t);
  setTimeout(() => t.remove(), 2500);
}

function showScreen(id) {
  document.querySelectorAll('#loading-screen, #login-screen, #main-screen').forEach(el => el.classList.add('hidden'));
  const el = document.getElementById(id);
  if (el) el.classList.remove('hidden');
}

function updateConnection(connected) {
  const status = $('#connection-status');
  if (!status) return;
  status.querySelector('.dot').className = `dot ${connected ? 'connected' : 'disconnected'}`;
  status.querySelector('span:last-child').textContent = connected ? 'Connected' : 'Disconnected';
}

function updateHWBadge(authorized) {
  const badge = $('#hw-badge');
  if (!badge) return;
  if (authorized === null) { badge.className = 'badge unknown'; badge.textContent = 'Checking...'; }
  else if (authorized) { badge.className = 'badge authorized'; badge.textContent = 'Authorized'; }
  else { badge.className = 'badge unauthorized'; badge.textContent = 'Unauthorized'; }
}

async function doLogin(username, password) {
  const btn = $('#login-btn');
  btn.disabled = true;
  btn.textContent = 'Connecting...';
  $('#login-error').classList.add('hidden');

  try {
    const ok = await api.login(username, password);
    if (!ok) { showLoginError('Login failed - check credentials or HWID'); return; }
    await enterMain();
  } catch (err) { showLoginError('Connection failed: ' + err.message); }
  finally { btn.disabled = false; btn.textContent = 'Connect'; }
}

function showLoginError(msg) {
  const el = $('#login-error');
  el.textContent = msg;
  el.classList.remove('hidden');
}

async function enterMain() {
  showScreen('main-screen');
  updateConnection(true);
  const hw = api.hardwareId || '';
  $('#version-text').textContent = hw ? `HW:${hw.slice(0, 8)}` : 'v1.21.10';
  await loadModules();
  await loadConfigs();
}

async function loadModules() {
  const modules = await api.getModules();
  if (!modules) return;
  modulesCache = modules;
  renderFilters(modules);
  renderModules(modules);
}

function renderFilters(modules) {
  const container = $('#filter-tabs');
  const counts = { all: modules.length };
  modules.forEach(m => {
    const cat = (m.category || 'Misc').toLowerCase();
    counts[cat] = (counts[cat] || 0) + 1;
  });
  container.innerHTML = Object.keys(counts).map(cat => {
    const active = cat === currentFilter ? 'active' : '';
    return `<button class="filter-btn ${active}" data-cat="${cat}">${cat} <span class="count">${counts[cat]}</span></button>`;
  }).join('');
  container.querySelectorAll('.filter-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      currentFilter = btn.dataset.cat;
      container.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      renderModules(modules);
    });
  });
}

function renderModules(modules) {
  const grid = $('#modules-grid');
  const search = ($('#search-input')?.value || '').toLowerCase();
  const filtered = modules.filter(m => {
    const cat = (m.category || 'Misc').toLowerCase();
    if (currentFilter !== 'all' && cat !== currentFilter) return false;
    if (search && !m.name.toLowerCase().includes(search)) return false;
    return true;
  });

  if (!filtered.length) {
    grid.innerHTML = '<div style="text-align:center;padding:40px;color:var(--text-secondary)">No modules found</div>';
    return;
  }

  grid.innerHTML = filtered.map(m => `
    <div class="module-card ${m.enabled ? 'module-card-enabled' : 'module-card-disabled'}">
      <div class="module-card-header">
        <span class="module-card-name">${esc(m.name)}</span>
        <span class="module-card-category">${m.category || 'Misc'}</span>
      </div>
      <div class="module-card-desc">${esc(m.description || '')}</div>
      <div class="module-card-footer">
        <label class="toggle">
          <input type="checkbox" ${m.enabled ? 'checked' : ''} data-name="${esc(m.name)}" />
          <span class="toggle-slider"></span>
        </label>
        ${m.hasSettings ? `<button class="settings-btn" data-name="${esc(m.name)}">Settings</button>` : ''}
      </div>
    </div>
  `).join('');

  grid.querySelectorAll('.toggle input').forEach(cb => {
    cb.addEventListener('change', async () => {
      const name = cb.dataset.name;
      const ok = await api.toggleModule(name, cb.checked);
      if (ok) { toast(`${name} ${cb.checked ? 'enabled' : 'disabled'}`); loadModules(); }
      else { cb.checked = !cb.checked; toast('Failed to toggle', 'error'); }
    });
  });

  grid.querySelectorAll('.settings-btn').forEach(btn => {
    btn.addEventListener('click', () => openSettings(btn.dataset.name));
  });
}

async function openSettings(moduleName) {
  if (settingsModalOpen) return;
  settingsModalOpen = true;

  const modal = $('#settings-modal');
  modal.classList.remove('hidden');
  $('#modal-module-name').textContent = moduleName;
  $('#modal-body').innerHTML = '<div class="loader" style="margin:20px auto"></div>';

  const settings = await api.getModuleSettings(moduleName);
  if (!settings) {
    $('#modal-body').innerHTML = '<p style="text-align:center;color:var(--text-secondary)">Failed to load settings</p>';
    return;
  }

  $('#modal-body').innerHTML = settings.map(s => {
    let control = '';
    switch (s.type) {
      case 'bool': {
        const checked = s.value ? 'checked' : '';
        control = `<label class="toggle"><input type="checkbox" ${checked} /><span class="toggle-slider"></span></label>`;
        break;
      }
      case 'int':
      case 'float': {
        const step = s.type === 'int' ? '1' : '0.1';
        control = `<div class="slider-row">
          <input type="range" min="${s.min}" max="${s.max}" step="${step}" value="${s.value}" />
          <span class="slider-value">${s.value}</span>
        </div>`;
        break;
      }
      case 'dropdown': {
        const opts = (s.modes || []).map((mode, i) =>
          `<option value="${i}" ${i === s.index ? 'selected' : ''}>${mode}</option>`
        ).join('');
        control = `<select class="setting-select">${opts}</select>`;
        break;
      }
      case 'keybind': control = `<span class="setting-value">${s.keyName || 'None'}</span>`; break;
      case 'color': control = `<span class="setting-value">RGB: ${s.value}</span>`; break;
      default: control = `<span class="setting-value">${s.value}</span>`;
    }
    return `<div class="setting-item" data-type="${s.type}" data-name="${esc(s.name)}">
      <div class="setting-header"><span class="setting-name">${esc(s.name)}</span>${control}</div>
      <div class="setting-desc">${esc(s.description || '')}</div>
    </div>`;
  }).join('');

  $('#modal-body').querySelectorAll('.setting-item[data-type="bool"]').forEach(item => {
    const cb = item.querySelector('input[type="checkbox"]');
    cb.addEventListener('change', async () => {
      const ok = await api.updateSetting(moduleName, item.dataset.name, cb.checked ? 'true' : 'false', 'bool');
      if (!ok) { cb.checked = !cb.checked; toast('Failed', 'error'); } else toast(`${item.dataset.name}: ${cb.checked ? 'on' : 'off'}`);
    });
  });

  $('#modal-body').querySelectorAll('.setting-item[data-type="int"], .setting-item[data-type="float"]').forEach(item => {
    const slider = item.querySelector('input[type="range"]');
    const valDisplay = item.querySelector('.slider-value');
    let timeout;
    slider.addEventListener('input', () => {
      valDisplay.textContent = slider.value;
      clearTimeout(timeout);
      timeout = setTimeout(async () => {
        const ok = await api.updateSetting(moduleName, item.dataset.name, slider.value, item.dataset.type);
        if (!ok) toast('Failed', 'error'); else toast(`${item.dataset.name}: ${slider.value}`);
      }, 400);
    });
  });

  $('#modal-body').querySelectorAll('.setting-item[data-type="dropdown"]').forEach(item => {
    const sel = item.querySelector('select');
    sel.addEventListener('change', async () => {
      const ok = await api.updateSetting(moduleName, item.dataset.name, sel.value, 'dropdown');
      if (!ok) toast('Failed', 'error'); else toast(`${item.dataset.name}: ${sel.options[sel.selectedIndex].text}`);
    });
  });

  const closeModal = () => { modal.classList.add('hidden'); settingsModalOpen = false; };
  $('#modal-backdrop').onclick = closeModal;
  $('#modal-close').onclick = closeModal;
}

async function loadConfigs() {
  const list = $('#configs-list');
  const configs = await api.getConfigs();
  const current = await api.getCurrentConfig();
  $('#current-config-name').textContent = current?.currentConfig || 'default';

  if (!configs || !configs.length) {
    list.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text-secondary)">No saved configs</div>';
    return;
  }

  list.innerHTML = configs.map(c => {
    const badges = [];
    if (c.isLastUsed) badges.push('Current');
    if (c.isDefault) badges.push('Default');
    const badgeHtml = badges.map(b => `<span class="config-item-badge">${b}</span>`).join(' ');
    return `<div class="config-item" data-name="${esc(c.name)}">
      <div class="config-item-left">
        <span class="config-item-name">${esc(c.name)} ${badgeHtml}</span>
        <span class="config-item-meta">${c.timestamp} &middot; ${c.size} bytes</span>
      </div>
      <button class="config-load-btn">Load</button>
    </div>`;
  }).join('');

  list.querySelectorAll('.config-load-btn').forEach(btn => {
    btn.addEventListener('click', async () => {
      const name = btn.closest('.config-item').dataset.name;
      const ok = await api.loadConfig(name);
      if (ok) { toast(`Loaded: ${name}`); loadConfigs(); loadModules(); }
      else toast('Failed to load config', 'error');
    });
  });
}

function esc(s) {
  if (!s) return '';
  const d = document.createElement('div');
  d.textContent = s;
  return d.innerHTML;
}

// ====================== TABS ======================
$$('.tab').forEach(tab => {
  tab.addEventListener('click', () => {
    $$('.tab').forEach(t => t.classList.remove('active'));
    tab.classList.add('active');
    $$('.tab-content').forEach(tc => tc.classList.remove('active'));
    document.getElementById(tab.dataset.tab + '-tab')?.classList.add('active');
  });
});

// ====================== INIT ======================
async function init() {
  showScreen('loading-screen');
  updateHWBadge(null);
  updateConnection(false);

  // Step 1: Authenticate with Discord (if inside Discord client)
  try {
    await setupDiscord();
    const authResult = await authorize();
    if (authResult) {
      console.log(`Discord user: ${authResult.user.username} (${authResult.user.id})`);
    } else {
      console.log('Running outside Discord or auth skipped');
    }
  } catch (err) {
    console.log('Not in Discord environment, running standalone');
  }

  // Step 2: Detect and connect to Pika ABSADA API
  const detected = await api.detect();
  if (!detected) {
    $('#loading-screen p').textContent = 'No Pika client detected';
    showScreen('login-screen');
    updateConnection(false);
    updateHWBadge(false);
    return;
  }

  // Step 3: Try auto-login
  const status = await api.getStatus();
  if (status && status.authenticated && status.hardwareAuthorized) {
    await enterMain();
    return;
  }

  // Step 4: Show login form
  showScreen('login-screen');
  updateConnection(true);
  updateHWBadge(status?.hardwareAuthorized ?? null);
}

// ====================== EVENTS ======================
$('#login-form').addEventListener('submit', (e) => { e.preventDefault(); doLogin($('#username').value, $('#password').value); });
$('#save-config-btn').addEventListener('click', async () => {
  const name = prompt('Config name:');
  if (name && await api.saveConfig(name)) { toast(`Saved: ${name}`); loadConfigs(); }
  else toast('Failed to save', 'error');
});
$('#refresh-configs-btn').addEventListener('click', loadConfigs);
$('#search-input').addEventListener('input', () => renderModules(modulesCache));

// Custom API URL
$('#advanced-toggle').addEventListener('click', () => {
  $('#advanced-panel').classList.toggle('hidden');
});
$('#custom-url-btn').addEventListener('click', async () => {
  const url = $('#custom-api-url').value.trim();
  if (!url) { toast('Enter a URL', 'error'); return; }
  api.setCustomUrl(url.replace(/\/+$/, ''));
  const detected = await api.detect();
  if (detected) {
    toast('Connected via custom URL');
    const status = await api.getStatus();
    if (status && status.authenticated && status.hardwareAuthorized) { await enterMain(); return; }
    showScreen('login-screen');
    updateConnection(true);
    updateHWBadge(status?.hardwareAuthorized ?? null);
  } else {
    api.clearCustomUrl();
    toast('Failed to connect via custom URL', 'error');
  }
});

init();
