const ABSADA_DEFAULT = 'http://localhost:3001';
const STORAGE_KEY = 'pika_api_url';

export class PikaAPI {
  constructor() {
    this.baseUrl = null;
    this.sessionCookie = null;
    this.token = null;
    this.isAuthenticated = false;
    this.hardwareAuthorized = false;
    this.hardwareId = null;
    this.connected = false;
    this.usingProxy = false;
  }

  async detect() {
    // 1. Check localStorage for a saved custom URL
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const res = await fetch(`${saved}/api/status`, {
          credentials: 'include', headers: { 'Accept': 'application/json' }, mode: 'cors',
        });
        if (res.ok) { this.baseUrl = saved; this.connected = true; return true; }
      } catch {}
    }

    // 2. Try direct localhost:3001 (works when deployed and CORS allows)
    try {
      const res = await fetch(`${ABSADA_DEFAULT}/api/status`, {
        credentials: 'include', headers: { 'Accept': 'application/json' }, mode: 'cors',
      });
      if (res.ok) {
        this.baseUrl = ABSADA_DEFAULT; this.connected = true; return true;
      }
    } catch {}

    // 3. Try Vite proxy (dev mode)
    try {
      const res = await fetch('/api/status', {
        credentials: 'include', headers: { 'Accept': 'application/json' },
      });
      if (res.ok) {
        this.baseUrl = ''; this.usingProxy = true; this.connected = true; return true;
      }
    } catch {}

    return false;
  }

  setCustomUrl(url) {
    localStorage.setItem(STORAGE_KEY, url);
    this.baseUrl = url;
    this.usingProxy = false;
    this.connected = true;
  }

  clearCustomUrl() {
    localStorage.removeItem(STORAGE_KEY);
  }

  _url(endpoint) {
    return this.usingProxy ? endpoint : `${this.baseUrl}${endpoint}`;
  }

  async request(endpoint, options = {}) {
    const url = this._url(endpoint);
    const headers = {
      'Accept': 'application/json',
      ...options.headers,
    };
    if (this.sessionCookie) headers['Cookie'] = `session=${this.sessionCookie}`;
    if (this.token) headers['Authorization'] = `Bearer ${this.token}`;

    const res = await fetch(url, { ...options, headers, credentials: 'include' });

    const setCookie = res.headers.get('set-cookie');
    if (setCookie) {
      const m = setCookie.match(/session=([^;]+)/);
      if (m) this.sessionCookie = m[1];
    }
    return res;
  }

  async login(username, password) {
    const form = new URLSearchParams({ username, password });
    const res = await this.request('/api/login', {
      method: 'POST',
      body: form,
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    });
    if (res.status !== 200) return false;
    const data = await res.json();
    if (data.success) {
      this.isAuthenticated = true;
      this.token = data.token;
      this.hardwareAuthorized = data.hardwareAuthorized;
      this.hardwareId = data.hardwareId;
      return true;
    }
    return false;
  }

  async getStatus() {
    const res = await this.request('/api/status');
    if (res.status !== 200) return null;
    const data = await res.json();
    this.isAuthenticated = data.authenticated;
    this.hardwareAuthorized = data.hardwareAuthorized;
    this.hardwareId = data.hardwareId;
    return data;
  }

  async getModules() {
    const res = await this.request('/api/modules');
    if (res.status !== 200) return null;
    return res.json();
  }

  async getModuleSettings(moduleName) {
    const res = await this.request(`/api/settings?module=${encodeURIComponent(moduleName)}`);
    if (res.status !== 200) return null;
    return res.json();
  }

  async toggleModule(moduleName, enabled) {
    const form = new URLSearchParams({ module: moduleName, enabled: String(enabled) });
    const res = await this.request('/api/toggle', {
      method: 'POST', body: form,
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    });
    if (res.status !== 200) return false;
    return (await res.json()).success;
  }

  async updateSetting(moduleName, settingName, value, type) {
    const form = new URLSearchParams({ module: moduleName, setting: settingName, value: String(value), type: type || '' });
    const res = await this.request('/api/update-setting', {
      method: 'POST', body: form,
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    });
    if (res.status !== 200) return false;
    return (await res.json()).success;
  }

  async keybindAction(moduleName, settingName, action, keyCode) {
    const res = await this.request('/api/keybind', {
      method: 'POST',
      body: JSON.stringify({ module: moduleName, setting: settingName, action, keyCode }),
      headers: { 'Content-Type': 'application/json' },
    });
    if (res.status !== 200) return null;
    return res.json();
  }

  async getConfigs() {
    const res = await this.request('/api/list-configs');
    if (res.status !== 200) return null;
    return res.json();
  }

  async loadConfig(name) {
    const form = new URLSearchParams({ name });
    const res = await this.request('/api/load-config', {
      method: 'POST', body: form,
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    });
    if (res.status !== 200) return false;
    return (await res.json()).success;
  }

  async saveConfig(name) {
    const form = new URLSearchParams({ name });
    const res = await this.request('/api/save-config', {
      method: 'POST', body: form,
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    });
    if (res.status !== 200) return false;
    return (await res.json()).success;
  }

  async getCurrentConfig() {
    const res = await this.request('/api/current-config');
    if (res.status !== 200) return null;
    return res.json();
  }
}
